export function useUser() {
  return useQuery({ queryKey: ["user"], queryFn: fetchUser });
}

// --- hooks/useOrders.ts (data fetching concern) ---
export function useOrders(userId: string) {
  return useQuery({
    queryKey: ["orders", userId],
    queryFn: () => fetchOrders(userId),
  });
}

