function DashboardPage() {
  const { data: user, isLoading } = useUser();
  const { data: orders } = useOrders(user?.id);

  if (isLoading) return <Spinner />;
  return (
    <div>
      <ProfileEditor user={user} />
      <OrderTable orders={orders ?? []} />
    </div>
  );
